Sub 'SetDDOSortedStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
DDO_Grid.SortedStatus = &OrderedBy.ToString().Trim() + !':' + iif(&OrderedDsc, !'DSC', !'ASC')
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&AuditRecordUser1.Visible = False &AuditRecordOperation1.Visible = False Do Case Case &DynamicFiltersSelector1 = !'AUDITRECORDUSER' &AuditRecordUser1.Visible = True Case &DynamicFiltersSelector1 = !'AUDITRECORDOPERATION' &AuditRecordOperation1.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&AuditRecordUser2.Visible = False &AuditRecordOperation2.Visible = False Do Case Case &DynamicFiltersSelector2 = !'AUDITRECORDUSER' &AuditRecordUser2.Visible = True Case &DynamicFiltersSelector2 = !'AUDITRECORDOPERATION' &AuditRecordOperation2.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&AuditRecordUser3.Visible = False &AuditRecordOperation3.Visible = False Do Case Case &DynamicFiltersSelector3 = !'AUDITRECORDUSER' &AuditRecordUser3.Visible = True Case &DynamicFiltersSelector3 = !'AUDITRECORDOPERATION' &AuditRecordOperation3.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'ResetDynFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled2 = False &DynamicFiltersSelector2 = !'AUDITRECORDUSER' &AuditRecordUser2.SetEmpty() Do 'EnableDynamicFilters2'
&DynamicFiltersEnabled3 = False &DynamicFiltersSelector3 = !'AUDITRECORDUSER' &AuditRecordUser3.SetEmpty() Do 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(&PgmName + !"GridState") = !"" &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState")) Else &GridState.FromXml(&Session.Get(&PgmName + !"GridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc Do 'SetDDOSortedStatus'
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"AUDITRECORDKEYVALUE" &AuditRecordKeyValue.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"AUDITRECORDTABLEGUID" &AuditRecordTableGuid.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"AUDITRECORDDATE" &AuditRecordDate.FromString(&GridStateFilterValue.Value) &AuditRecordDate_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"AUDITRECORDATTRIBUTESNEWVALUE" &AuditRecordAttributesNewValue.FromString(&GridStateFilterValue.Value) EndCase EndFor Do 'LoadDynFiltersState' If not &GridState.PageSize.Trim().IsEmpty() Grid.Rows = &GridState.PageSize.ToNumeric() EndIf Grid.CurrentPage = &GridState.CurrentPage
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
AddDynamicFilters1.Visible = True RemoveDynamicFilters1.Visible = False AddDynamicFilters2.Visible = True RemoveDynamicFilters2.Visible = False
If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'AUDITRECORDUSER' &AuditRecordUser1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'AUDITRECORDOPERATION' &AuditRecordOperation1.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters1' If &GridState.DynamicFilters.Count >= 2 JSDynamicFilters.Caption = !'<script type="text/javascript">$(document).ready(function() {' JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 2, 2);", TableDynamicFilters.InternalName) AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'AUDITRECORDUSER' &AuditRecordUser2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'AUDITRECORDOPERATION' &AuditRecordOperation2.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters2' If &GridState.DynamicFilters.Count >= 3 JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 3, 2);", TableDynamicFilters.InternalName) AddDynamicFilters2.Visible = False RemoveDynamicFilters2.Visible = True &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'AUDITRECORDUSER' &AuditRecordUser3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'AUDITRECORDOPERATION' &AuditRecordOperation3.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters3' EndIf JSDynamicFilters.Caption += !'});</script>' EndIf EndIf If &DynamicFiltersRemoving JSDynamicFilters.Caption = '' EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.FromXml(&Session.Get(&PgmName + !"GridState"))
// Save grid state in session. &GridState.OrderedBy = &OrderedBy &GridState.OrderedDsc = &OrderedDsc &GridState.FilterValues.Clear() WWP_GridStateAddFilterValue(&GridState, !"AUDITRECORDKEYVALUE", "", not &AuditRecordKeyValue.IsEmpty(), 0, &AuditRecordKeyValue, '') WWP_GridStateAddFilterValue(&GridState, !"AUDITRECORDTABLEGUID", "", not &AuditRecordTableGuid.IsEmpty(), 0, &AuditRecordTableGuid, '') WWP_GridStateAddFilterValue(&GridState, !"AUDITRECORDDATE", "", not (&AuditRecordDate.IsEmpty() AND &AuditRecordDate_To.IsEmpty()), 0, &AuditRecordDate.ToString().Trim(), &AuditRecordDate_To.ToString().Trim()) WWP_GridStateAddFilterValue(&GridState, !"AUDITRECORDATTRIBUTESNEWVALUE", "", not &AuditRecordAttributesNewValue.IsEmpty(), 0, &AuditRecordAttributesNewValue, '')
Do 'SaveDynFiltersState'
&GridState.PageSize = str(Grid.Rows) &GridState.CurrentPage = Grid.CurrentPage SaveGridState.Call(&PgmName + !"GridState", &GridState.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.DynamicFilters.Clear() If not &DynamicFiltersIgnoreFirst &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector1 Do Case Case &DynamicFiltersSelector1 = !'AUDITRECORDUSER' AND not &AuditRecordUser1.IsEmpty() &GridStateDynamicFilter.Value = &AuditRecordUser1.ToString() Case &DynamicFiltersSelector1 = !'AUDITRECORDOPERATION' AND not &AuditRecordOperation1.IsEmpty() &GridStateDynamicFilter.Value = &AuditRecordOperation1.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled2 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector2 Do Case Case &DynamicFiltersSelector2 = !'AUDITRECORDUSER' AND not &AuditRecordUser2.IsEmpty() &GridStateDynamicFilter.Value = &AuditRecordUser2.ToString() Case &DynamicFiltersSelector2 = !'AUDITRECORDOPERATION' AND not &AuditRecordOperation2.IsEmpty() &GridStateDynamicFilter.Value = &AuditRecordOperation2.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled3 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector3 Do Case Case &DynamicFiltersSelector3 = !'AUDITRECORDUSER' AND not &AuditRecordUser3.IsEmpty() &GridStateDynamicFilter.Value = &AuditRecordUser3.ToString() Case &DynamicFiltersSelector3 = !'AUDITRECORDOPERATION' AND not &AuditRecordOperation3.IsEmpty() &GridStateDynamicFilter.Value = &AuditRecordOperation3.ToString() EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrepareTransaction'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&TrnContext = new() &TrnContext.CallerObject = &Pgmname &TrnContext.CallerOnDelete = True &TrnContext.CallerURL = &HTTPRequest.ScriptName + !"?" + &HTTPRequest.QueryString &TrnContext.TransactionName = !"AuditRecord"
&Session.Set(!"TrnContext", &TrnContext.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Event &AuditRecordTableGuid.Click
Do 'Update AuditRecordAttributesNewValue Satus'
EndEvent
Event &Visualizar.Click
viewAuditRecordJaspi.Link(AuditRecordId)
EndEvent
Sub 'Update AuditRecordAttributesNewValue Satus'
If &AuditRecordTableGuid.IsEmpty() &AuditRecordAttributesNewValue.SetEmpty() &AuditRecordAttributesNewValue.Visible = False
DynamicFiltersFixedFilterCaptionAuditRecordAttributesNewValue.Class = DynamicFiltersFixedFilterCaptionAuditRecordAttributesNewValue.Class + !' Invisible'
Else &AuditRecordAttributesNewValue.Visible = True
DynamicFiltersFixedFilterCaptionAuditRecordAttributesNewValue.Class = StrReplace(DynamicFiltersFixedFilterCaptionAuditRecordAttributesNewValue.Class, !' Invisible', '')
EndIf
EndSub

